def test_tc_gw_failsafe_door_001_no_warning_when_signal_ok(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) in (0, 1)

def test_tc_gw_failsafe_door_002_timeout_flag_set(can_bus):
    msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_door_signal_timeout(msg) == 1

def test_tc_gw_failsafe_door_003_fail_safe_warning_active(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_failsafe_door_004_ignore_individual_doors(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_failsafe_door_005_warning_persistent(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 3)
    assert msgs
    for msg in msgs:
        assert decode_any_door_open(msg) == 1

def test_tc_gw_failsafe_door_006_recovery_after_signal_resume(can_bus):
    fault_msgs = collect_messages(can_bus, GW_FAULT_STATUS_ID, 3)
    assert fault_msgs
    for msg in fault_msgs:
        assert decode_door_signal_timeout(msg) in (0, 1)

def test_tc_gw_failsafe_door_007_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_DOOR_STATUS_ID, 2)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_DOOR_STATUS_DLC
